                    if medication_codeable_concept.get('text'):
                        covid_text = covid_text + ' ' + medication_codeable_concept.get('text')

                    med_codings = medication_codeable_concept.get('coding', [])
                    coding_index = 0
                    while coding_index < len(med_codings):
                        coding = med_codings[coding_index]
                        if coding.get('display'):
