                        coding_index += 1

                    if request_code.get('text'):
                        covid_text = covid_text + ' ' + request_code.get('text')

                    normalized_text = covid_text.lower()
                    is_covid_related = False
                    if 'covid' in normalized_text:
                        is_covid_related = True
                    if 'sars-cov' in normalized_text:
                        is_covid_related = True
                    if 'booster' in normalized_text and ('vaccine' in normalized_text or 'immunization' in normalized_text):
